it("quote for 2 runes should have 50 G base premium (2 x 25 G, no block)", () => {
  const result = processScenario({
    customer: { yearsWithMHPCO: 0 },
    steps: [
      {
        op: "quote",
        items: [{ type: "rune" }, { type: "rune" }],
      },
    ],
  });
  expect(result).toEqual({ results: [{ premium: 60 }] });
});

